#!/usr/bin/env node
/**
 * Generate public/llms.txt from the content repo rules and categories.
 *
 * Expected workspace layout (relative to repo root):
 *   category-uri-title-map.json                      – generated by build-rule-category-map.py
 *   rule-to-categories.json                           – generated by build-rule-category-map.py
 *   content/public/uploads/rules/<uri>/rule.mdx       – checked-out SSW.Rules.Content
 *
 * Usage:
 *   node generate-llms-txt.js [content-rules-dir]
 *
 * The rules directory is resolved in order:
 *   1. CLI argument (process.argv[2])
 *   2. CONTENT_RULES_DIR env var
 *   3. Default: content/public/uploads/rules/ (relative to repo root)
 *
 * Output:
 *   public/llms.txt
 */

const fs = require("node:fs");
const path = require("node:path");

// ── Path setup ────────────────────────────────────────────────────────────────
const REPO_ROOT = path.resolve(__dirname, "..");

const CATEGORY_MAP_FILE = path.join(REPO_ROOT, "category-uri-title-map.json");
const RULE_CATEGORY_FILE = path.join(REPO_ROOT, "rule-to-categories.json");
const CONTENT_RULES_DIR =
  process.argv[2] ||
  process.env.CONTENT_RULES_DIR ||
  path.join(REPO_ROOT, "content", "public", "uploads", "rules");
const OUTPUT_FILE = path.join(REPO_ROOT, "public", "llms.txt");

const SITE_URL = "https://www.ssw.com.au/rules";

// ── Helpers ───────────────────────────────────────────────────────────────────

const FRONTMATTER_RE = /^---\s*\n([\s\S]*?)\n?---/;
const TITLE_RE = /^title\s*:\s*["']?(.*?)["']?\s*$/m;
const ARCHIVED_VALUE_RE = /^archivedreason\s*:\s*(.+)$/im;

/**
 * Return { title, archived } for a rule, or null if the MDX file is missing.
 */
function readRuleMeta(ruleUri) {
  const mdxPath = path.join(CONTENT_RULES_DIR, ruleUri, "rule.mdx");

  if (!fs.existsSync(mdxPath)) {
    return null;
  }

  // Read only the first 4 KB – frontmatter is always near the top
  const fd = fs.openSync(mdxPath, "r");
  const buffer = Buffer.alloc(4096);
  const bytesRead = fs.readSync(fd, buffer, 0, 4096, 0);
  fs.closeSync(fd);
  const content = buffer.toString("utf-8", 0, bytesRead);

  const fmMatch = content.match(FRONTMATTER_RE);
  if (!fmMatch) return null;

  const frontmatter = fmMatch[1];

  const titleMatch = frontmatter.match(TITLE_RE);
  if (!titleMatch) return null;

  const title = titleMatch[1].trim().replace(/^["']|["']$/g, "");

  // Check if rule is archived: archivedreason must have a real value (not null/empty)
  let archived = false;
  const arMatch = frontmatter.match(ARCHIVED_VALUE_RE);
  if (arMatch) {
    const value = arMatch[1].trim().replace(/^["']|["']$/g, "").toLowerCase();
    archived = value !== "null" && value !== "";
  }

  return { title, archived };
}

// ── Main ──────────────────────────────────────────────────────────────────────

function main() {
  // Load mapping files
  const categoryMap = JSON.parse(
    fs.readFileSync(CATEGORY_MAP_FILE, "utf-8"),
  ).categories || {};

  const ruleToCategoriesRaw = JSON.parse(
    fs.readFileSync(RULE_CATEGORY_FILE, "utf-8"),
  );

  // Build category -> list-of-rule-uris (active rules only)
  const categoryRules = {};
  for (const cat of Object.keys(categoryMap)) {
    categoryRules[cat] = [];
  }

  let rulesFound = 0;
  let rulesArchived = 0;
  let rulesMissing = 0;

  for (const [ruleUri, categories] of Object.entries(ruleToCategoriesRaw)) {
    const meta = readRuleMeta(ruleUri);
    if (meta === null) {
      rulesMissing++;
      continue;
    }
    if (meta.archived) {
      rulesArchived++;
      continue;
    }
    rulesFound++;
    for (const catUri of categories) {
      if (catUri in categoryRules) {
        categoryRules[catUri].push(ruleUri);
      }
    }
  }

  // Sort rules within each category alphabetically by URI
  for (const catUri of Object.keys(categoryRules)) {
    categoryRules[catUri].sort();
  }

  // Generate llms.txt
  const lines = [
    "# SSW Rules",
    "> Secret Ingredients to Quality Software \u2013 best practices for software development and project management.",
    `> Source: ${SITE_URL}/`,
    "",
  ];

  // Sort categories alphabetically by title
  const sortedCategories = Object.entries(categoryMap).sort((a, b) =>
    a[1].localeCompare(b[1]),
  );

  for (const [catUri, catTitle] of sortedCategories) {
    const rules = categoryRules[catUri] || [];
    if (rules.length === 0) continue;

    lines.push(`## [${catTitle}](${SITE_URL}/${catUri}/)`);
    lines.push("");

    for (const ruleUri of rules) {
      const meta = readRuleMeta(ruleUri);
      if (meta) {
        lines.push(`- [${meta.title}](${SITE_URL}/${ruleUri}/)`);
      }
    }

    lines.push("");
  }

  // Write output
  fs.mkdirSync(path.dirname(OUTPUT_FILE), { recursive: true });
  fs.writeFileSync(OUTPUT_FILE, lines.join("\n"), "utf-8");

  console.log("\u2705  public/llms.txt generated");
  console.log(
    `   Categories with rules : ${Object.values(categoryRules).filter((r) => r.length > 0).length}`,
  );
  console.log(`   Active rules           : ${rulesFound}`);
  console.log(`   Archived (skipped)     : ${rulesArchived}`);
  console.log(`   Missing MDX (skipped)  : ${rulesMissing}`);
}

// ── Entry point ───────────────────────────────────────────────────────────────

if (!fs.existsSync(CONTENT_RULES_DIR)) {
  console.error(`ERROR: content rules directory not found: ${CONTENT_RULES_DIR}`);
  console.error(
    "Run this script after the content repo has been checked out to ./content",
  );
  process.exit(1);
}

main();
